uint p = thread_position_in_grid.x;
int pixelCount = int(counts_1[0]);
if (int(p) >= pixelCount) {
    return;
}
int gaussianCount = int(counts_1[1]);
bool whiteBg = counts_1[2] != 0;

float px = float(tileCoord_1[p * 2 + 0]);
float py = float(tileCoord_1[p * 2 + 1]);

float gColorX = cotColor_1[p * 3 + 0];
float gColorY = cotColor_1[p * 3 + 1];
float gColorZ = cotColor_1[p * 3 + 2];
float gDepth = cotDepth_1[p];
float gAlpha = cotAlpha_1[p];
float bgCoeff = whiteBg ? -(gColorX + gColorY + gColorZ) : 0.0f;

float weightedSum = 0.0f;
float trans = 1.0f;

for (int i = 0; i < gaussianCount; ++i) {
    float dx = px - sortedMeans2d_1[i * 2 + 0];
    float dy = py - sortedMeans2d_1[i * 2 + 1];
    uint conicBase = uint(i) * 4;
    float exponent = -0.5f * (
        dx * dx * sortedConic_1[conicBase + 0] +
        dy * dy * sortedConic_1[conicBase + 3] +
        dx * dy * sortedConic_1[conicBase + 1] +
        dx * dy * sortedConic_1[conicBase + 2]
    );
    float raw = exp(exponent) * sortedOpacity_1[i];
    float alpha = raw;
    if (alpha > 0.99f) {
        alpha = 0.99f;
    }

    float contrib = trans * alpha;
    uint colorBase = uint(i) * 3;
    float c = (
        gColorX * sortedColor_1[colorBase + 0] +
        gColorY * sortedColor_1[colorBase + 1] +
        gColorZ * sortedColor_1[colorBase + 2]
    ) + gDepth * sortedDepths_1[i] + gAlpha + bgCoeff;
    weightedSum += c * contrib;

    trans *= (1.0f - alpha);
    if (trans < 1e-4f) {
        break;
    }
}

trans = 1.0f;
float prefixWeighted = 0.0f;
for (int i = 0; i < gaussianCount; ++i) {
    float dx = px - sortedMeans2d_1[i * 2 + 0];
    float dy = py - sortedMeans2d_1[i * 2 + 1];
    uint conicBase = uint(i) * 4;
    float c00 = sortedConic_1[conicBase + 0];
    float c01 = sortedConic_1[conicBase + 1];
    float c10 = sortedConic_1[conicBase + 2];
    float c11 = sortedConic_1[conicBase + 3];
    float exponent = -0.5f * (
        dx * dx * c00 +
        dy * dy * c11 +
        dx * dy * c01 +
        dx * dy * c10
    );
    float expVal = exp(exponent);
    float raw = expVal * sortedOpacity_1[i];
    float alpha = raw;
    if (alpha > 0.99f) {
        alpha = 0.99f;
    }
    float contrib = trans * alpha;
    uint colorBase = uint(i) * 3;
    float c = (
        gColorX * sortedColor_1[colorBase + 0] +
        gColorY * sortedColor_1[colorBase + 1] +
        gColorZ * sortedColor_1[colorBase + 2]
    ) + gDepth * sortedDepths_1[i] + gAlpha + bgCoeff;

    float suffixWeighted = weightedSum - (prefixWeighted + c * contrib);
    float denom = 1.0f - alpha;
    if (denom < 1e-6f) {
        denom = 1e-6f;
    }
    float gradAlpha = c * trans - suffixWeighted / denom;

    atomic_fetch_add_explicit(
        (device atomic_float*)(gradSortedDepths_1 + i),
        gDepth * contrib,
        memory_order_relaxed
    );
    atomic_fetch_add_explicit(
        (device atomic_float*)(gradSortedColor_1 + colorBase + 0),
        gColorX * contrib,
        memory_order_relaxed
    );
    atomic_fetch_add_explicit(
        (device atomic_float*)(gradSortedColor_1 + colorBase + 1),
        gColorY * contrib,
        memory_order_relaxed
    );
    atomic_fetch_add_explicit(
        (device atomic_float*)(gradSortedColor_1 + colorBase + 2),
        gColorZ * contrib,
        memory_order_relaxed
    );

    if (raw <= 0.99f) {
        float gradRaw = gradAlpha;
        atomic_fetch_add_explicit(
            (device atomic_float*)(gradSortedOpacity_1 + i),
            gradRaw * expVal,
            memory_order_relaxed
        );

        float gradExponent = gradRaw * raw;
        float dxdy = dx * dy;
        atomic_fetch_add_explicit(
            (device atomic_float*)(gradSortedConic_1 + conicBase + 0),
            gradExponent * (-0.5f * dx * dx),
            memory_order_relaxed
        );
        atomic_fetch_add_explicit(
            (device atomic_float*)(gradSortedConic_1 + conicBase + 1),
            gradExponent * (-0.5f * dxdy),
            memory_order_relaxed
        );
        atomic_fetch_add_explicit(
            (device atomic_float*)(gradSortedConic_1 + conicBase + 2),
            gradExponent * (-0.5f * dxdy),
            memory_order_relaxed
        );
        atomic_fetch_add_explicit(
            (device atomic_float*)(gradSortedConic_1 + conicBase + 3),
            gradExponent * (-0.5f * dy * dy),
            memory_order_relaxed
        );

        float c01sum = c01 + c10;
        float gradDx = gradExponent * (-dx * c00 - 0.5f * dy * c01sum);
        float gradDy = gradExponent * (-dy * c11 - 0.5f * dx * c01sum);

        atomic_fetch_add_explicit(
            (device atomic_float*)(gradSortedMeans2d_1 + i * 2 + 0),
            -gradDx,
            memory_order_relaxed
        );
        atomic_fetch_add_explicit(
            (device atomic_float*)(gradSortedMeans2d_1 + i * 2 + 1),
            -gradDy,
            memory_order_relaxed
        );
    }

    prefixWeighted += c * contrib;
    trans *= (1.0f - alpha);
    if (trans < 1e-4f) {
        break;
    }
}
